@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];
const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Feature coverage';
const columns=Array.isArray(data.columns)?data.columns:[];
const groups=Array.isArray(data.groups)?data.groups:[];
const featureCount=groups.reduce((sum,group)=>sum+(group&&Array.isArray(group.features)?group.features.length:0),0);
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading');
heading.appendChild(make('div','eyebrow','Feature matrix'));
heading.appendChild(make('h2','',title));
heading.appendChild(make('div','meta',columns.length+' option'+(columns.length===1?'':'s')+' · '+featureCount+' grouped features'));
frame.appendChild(heading);
if(!columns.length||!featureCount){
  frame.appendChild(make('div','empty','Add columns and grouped features to build the matrix.'));
}else{
  const scroll=make('div','scroll'); const table=make('table'); table.appendChild(make('caption','sr-only',title));
  const thead=make('thead'); const header=make('tr'); const corner=make('th','corner','Capability'); corner.scope='col'; header.appendChild(corner);
  columns.forEach((column)=>{
    const recommended=column&&column.highlight===true; const th=make('th','column'+(recommended?' recommended':'')); th.scope='col';
    if(recommended) th.appendChild(make('span','badge','Recommended'));
    th.appendChild(make('span','column-name',column&&column.name!=null?String(column.name):'Untitled'));
    if(column&&column.note) th.appendChild(make('span','column-note',String(column.note)));
    header.appendChild(th);
  });
  thead.appendChild(header); table.appendChild(thead); const tbody=make('tbody');
  groups.forEach((group)=>{
    const features=group&&Array.isArray(group.features)?group.features:[]; if(!features.length) return;
    const groupRow=make('tr','group-row'); const groupLabel=make('th','group-label',group&&group.label!=null?String(group.label):'Features'); groupLabel.scope='rowgroup'; groupRow.appendChild(groupLabel);
    const fill=make('td'); fill.colSpan=columns.length; fill.setAttribute('aria-hidden','true'); groupRow.appendChild(fill); tbody.appendChild(groupRow);
    features.forEach((feature)=>{
      const row=make('tr','data-row'); const th=make('th','feature'); th.scope='row';
      th.appendChild(make('span','feature-name',feature&&feature.label!=null?String(feature.label):'Untitled feature'));
      if(feature&&feature.note) th.appendChild(make('span','feature-note',String(feature.note))); row.appendChild(th);
      const values=feature&&feature.values&&typeof feature.values==='object'?feature.values:{};
      columns.forEach((column)=>{
        const td=make('td',column&&column.highlight===true?'recommended':''); const value=column&&column.id!=null?values[String(column.id)]:undefined;
        let mark;
        if(value===true){ mark=make('span','mark yes','✓'); mark.setAttribute('aria-label','Supported'); }
        else if(value===false){ mark=make('span','mark no','✗'); mark.setAttribute('aria-label','Not supported'); }
        else if(value==='partial'){ mark=make('span','mark partial','Partial'); mark.setAttribute('aria-label','Partially supported'); }
        else { mark=make('span','mark partial','—'); mark.setAttribute('aria-label','Unknown'); }
        td.appendChild(mark); row.appendChild(td);
      });
      tbody.appendChild(row);
    });
  });
  table.appendChild(tbody); scroll.appendChild(table); frame.appendChild(scroll);
}
root.appendChild(frame);
parent.appendChild(host);
